// Time:  O(26 * n)
// Space: O(26)

// freq table, greedy
class Solution {
public:
    string lexGreaterPermutation(string s, string target) {
        const auto& nxt = [](auto& cnt, int x) {
            for (int i = (x - 'a') + 1; i < size(cnt); ++i) {
                if (!cnt[i]) {
                    continue;
                }
                return static_cast<char>('a' + i);
            }
            return ' ';
        };

        vector<int> cnt(26);
        for (const auto& x : s) {
            ++cnt[x - 'a'];
        }
        vector<int> tmp(cnt);
        int j = -1;
        for (int i = 0; i < size(target); ++i) {
            const auto& y = nxt(tmp, target[i]);
            if (y != ' ') {
                j = i;
            }
            if (!tmp[target[i] - 'a']) {
                break;
            }
            --tmp[target[i] - 'a'];
        }
        string result;
        if (j == -1) {
            return result;
        }
        for (int i = 0; i < j; ++i) {
            result.push_back(target[i]);
            --cnt[target[i] - 'a'];
        }
        const auto& y = nxt(cnt, target[j]);
        result.push_back(y);
        --cnt[y - 'a'];
        for (int i = 0; i < size(cnt); ++i) {
            for (; cnt[i]; --cnt[i]) {
                result.push_back('a' + i);
            }
        }
        return result;
    }
};

# Time:  O(26 * n)
# Space: O(26)

# freq table, greedy
class Solution(object):
    def lexGreaterPermutation(self, s, target):
        """
        :type s: str
        :type target: str
        :rtype: str
        """
        def nxt(cnt, x):
            for i in xrange(ord(x)-ord('a')+1, len(cnt)):
                if not cnt[i]:
                    continue
                return chr(ord('a')+i)
            return ' '

        cnt = [0]*26
        for x in s:
            cnt[ord(x)-ord('a')] += 1
        tmp = cnt[:]
        j = -1
        for i, x in enumerate(target):
            y = nxt(tmp, x)
            if y != ' ':
                j = i
            if not tmp[ord(x)-ord('a')]:
                break
            tmp[ord(x)-ord('a')] -= 1
        if j == -1:
            return ""
        result = []
        for i in xrange(j):
            result.append(target[i])
            cnt[ord(target[i])-ord('a')] -= 1
        y = nxt(cnt, target[j])
        result.append(y)
        cnt[ord(y)-ord('a')] -= 1
        for i in xrange(len(cnt)):
            for _ in xrange(cnt[i]):
                result.append(chr(ord('a')+i))
                cnt[i] -= 1
        return "".join(result)
